import{_ as a}from"./zsxq-42e2301a.js";import{_ as i,Q as l,S as r,W as e,a4 as o,a2 as n,a5 as c,E as s}from"./framework-291a1352.js";const d="/assets/goal-f1a248e4.png",h="/assets/computer-3e379a9d.png",_={},p=c('<h1 id="如何制定有价值的目标" tabindex="-1"><a class="header-anchor" href="#如何制定有价值的目标" aria-hidden="true">#</a> 如何制定有价值的目标</h1><blockquote><p>写于2017年07月09日23:29</p></blockquote><blockquote><p>公司会制定一系列目标，个人也可以制定一些目标，有利于自我学习成长。那么看我这篇文章可以告诉你如何制定有价值的目标。会制定有价值的目标，绝对超越很多人。</p></blockquote><h2 id="smart原则" tabindex="-1"><a class="header-anchor" href="#smart原则" aria-hidden="true">#</a> SMART原则</h2><p>王健林之前说<strong>定个小目标，先赚它一个亿</strong>。然后就火了一把，各种推文，主要是关于定计划的。我清晰得记得有一天早上，去上班时路过一所学校，广播里校长引用了王健林这句话。其实目标管理要量身定做，且有一定原则。这时召唤下同级校友做的一页PPT，<strong>SMART原则</strong>。</p><figure><img src="'+d+'" alt="助力目标管理-SMART原则" tabindex="0" loading="lazy"><figcaption>助力目标管理-SMART原则</figcaption></figure><p>如果转换成简单好记一点就是：<strong>什么时间内，做什么事情，做到什么程度</strong>。</p><h2 id="记录时间" tabindex="-1"><a class="header-anchor" href="#记录时间" aria-hidden="true">#</a> 记录时间</h2><p>不过定目标不是那么容易，可以试着记录自己一周的时间或者说一个月的时间都做了什么。关于如何记录可以利用艾力老师的 <strong>“34枚金币时间管理法”</strong> ，通俗点讲就是一天17小时醒着，每半小时算一枚金币。记录了一个周时间后，就能发现自己什么时间在做什么。有一定针对性。</p><p>比如你随便定了个计划，一个月内，把年中618买的四本书看完，并记笔记。你可能就会发现一个月内，一天只能抽出一小时看书，一小时最多能看50页。而一本书平均300页。这样粗略一算，6天才能看完一本，还不包括记笔记。所以一个月看不完四本。</p><h2 id="戴明环-pdca" tabindex="-1"><a class="header-anchor" href="#戴明环-pdca" aria-hidden="true">#</a> 戴明环（PDCA）</h2><p>有人说，计划赶不上变化，所以不做计划。有一种东西叫做<strong>戴明环（PDCA）</strong>。拆开来就是：<code>计划(Plan)</code>、<code>实施(Do)</code>、<code>检查(Check)</code>、<code>行动(Action)</code>。</p><p>比如上面的例子，一个月看四本书。计划可能会被打断，去实施及时检查，再行动。也就是说原计划一个月看完4本书，每天看50页，发现看的这类书籍一小时完全看不完50页，就及时修正计划。看完就给自己一个小奖励（正反馈），比如吃一包麻辣冷静一下，这时再召唤一下我很早以前做的一张PPT（从修电脑中学到的万能学习模式）。</p><figure><img src="'+h+'" alt="从修电脑中学到的万能学习模式" tabindex="0" loading="lazy"><figcaption>从修电脑中学到的万能学习模式</figcaption></figure><p>这样虽然可能会延期到一个半月才看完，但这是有效的循环。<code>定目标——定计划——执行计划——检查回顾——巩固循环——定目标</code>。</p><h2 id="工具推荐" tabindex="-1"><a class="header-anchor" href="#工具推荐" aria-hidden="true">#</a> 工具推荐</h2><p>前面说了这么多，那么有没有工具来帮助我们定目标呢。答案是肯定的。</p>',17),u=e("code",null,"teambition",-1),m={href:"https://www.teambition.com/",target:"_blank",rel:"noopener noreferrer"},g=e("code",null,"滴答清单",-1),f={href:"https://www.dida365.com/",target:"_blank",rel:"noopener noreferrer"},b=e("code",null,"doit.im",-1),x={href:"http://doitim.com/cn/",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这三款软件，都有APP，各大应用商店可供下载。",-1),w=e("p",null,[o("这三款我都使用过，其中"),e("code",null,"doit.im"),o("、"),e("code",null,"滴答清单"),o("在大学期间用的比较多。现在用的比较多的是"),e("code",null,"teambition"),o("，免费版也支持日历功能。大家可以根据自己实际情况选择适合自己的。")],-1),A=e("h2",{id:"总结",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#总结","aria-hidden":"true"},"#"),o(" 总结")],-1),P=e("p",null,"总结一下：【目标管理】如何制定有价值的目标。 主要写了四点：",-1),T=e("li",null,"①SMART原则",-1),S=e("li",null,"②记录时间（34枚金币时间管理法）",-1),R=e("li",null,"③戴明环（PDCA）",-1),q=e("li",null,"teambition",-1),C=e("li",null,"滴答清单",-1),M={href:"http://doit.im",target:"_blank",rel:"noopener noreferrer"},N=e("p",null,"希望对大家有所启发。",-1),V=e("p",null,"这是我2017年在知识星球写的推文。",-1),D=e("blockquote",null,[e("p",null,[o("知识星球"),e("code",null,"前端视野 若川"),o("简介：主要发表一些前端所见所想，Vue、React、构建工具(比如：gulp、webpack)、Nodejs、设计模式等。一个人走得快，一群人走得远。"),e("br"),o(" 公众号文章不常更新，知识星球更新相对多一些。2017年开通至今，一直没怎么宣传，目前有"),e("code",null,"960余人"),o("加入了我的知识星球，欢迎识别二维码"),e("code",null,"免费加入"),o("。 "),e("img",{src:a,alt:"前端视野-主要写前端的所见所想",loading:"lazy"})])],-1);function E(v,y){const t=s("ExternalLinkIcon");return l(),r("div",null,[p,e("p",null,[o("非常推荐"),u,o("，网站："),e("a",m,[o("https://www.teambition.com/"),n(t)])]),e("p",null,[o("推荐"),g,o("，网站："),e("a",f,[o("https://www.dida365.com/"),n(t)])]),e("p",null,[o("最后推荐"),b,o("，网站："),e("a",x,[o("http://doitim.com/cn/"),n(t)])]),k,w,A,P,e("ul",null,[T,S,R,e("li",null,[o("④工具推荐 "),e("ul",null,[q,C,e("li",null,[e("a",M,[o("doit.im"),n(t)])])])])]),N,V,D])}const I=i(_,[["render",E],["__file","index.html.vue"]]);export{I as default};
